{
  "title": "TFM - Reducci\u00f3n por regla",
  "type": "table",
  "aggs": [
    {
      "id": "1",
      "enabled": true,
      "type": "terms",
      "params": {
        "field": "rule.id",
        "orderBy": "2",
        "order": "desc",
        "size": 30,
        "otherBucket": false,
        "missingBucket": false,
        "customLabel": "Rule ID"
      },
      "schema": "bucket"
    },
    {
      "id": "2",
      "enabled": true,
      "type": "sum",
      "params": {
        "field": "count",
        "customLabel": "Alertas brutas"
      },
      "schema": "metric"
    },
    {
      "id": "3",
      "enabled": true,
      "type": "count",
      "params": {
        "customLabel": "Filas dedupeadas"
