    {
      "id": "5",
      "enabled": true,
      "type": "max",
      "params": {
        "field": "rule.level",
        "customLabel": "Nivel"
      },
      "schema": "metric"
    }
  ],
  "params": {
    "perPage": 15,
    "showPartialRows": false,
    "showMetricsAtAllLevels": false,
    "showTotal": true,
    "totalFunc": "sum",
    "percentageCol": ""
  }
}

{
  "title": "TFM - Comunidades con contexto",
